beginning.embedded_functions:
/**
 * Return:
 * - 0: ok
 * - 1: invalid
 * - 2: NULL
 */
static inline int em_check_ngap_setup_procedure(const ngap_t *ngap) {
    // Check for repeated NGSetupRequest and NGSetupResponse messages
    if (ngap->procedure_code == PROCEDURE_CODE_NG_SETUP_REQUEST && ngap->pdu_present == TRUE) {
        return 1;
    } else if (ngap->procedure_code == PROCEDURE_CODE_NG_SETUP_RESPONSE && ngap->pdu_present == TRUE) {
        return 2;
    }
    return 0;
}

static inline int em_check_sctp_association(const sctp_t *sctp) {
    // Check for short-lived associations and cyclic reconnect behavior
    if (sctp->association_setup_count > 5 && sctp->association_teardown_count > 5) {
        return 1;
    }
    return 0;
}

static inline int em_check_ngap_reset(const ngap_t *ngap) {
    // Check for NGReset messages
    if (ngap->procedure_code == PROCEDURE_CODE_NG_RESET && ngap->pdu_present == TRUE) {
        return 1;
    }
    return 0;
}

static inline int em_check_gnb_reconnects(const ngap_t *ngap, const sctp_t *sctp) {
    // Check for repeated NG setup procedures within a bounded time window
    if (ngap->procedure_code == PROCEDURE_CODE_NG_SETUP_REQUEST && ngap->pdu_present == TRUE) {
        return 1;
    } else if (sctp->association_setup_count > 5 && sctp->association_teardown_count > 5) {
        return 2;
    }
    return 0;
}
